SELECT T2.* FROM (
    SELECT ROW_NUMBER() OVER(ORDER BY CN_SERIAL) AS RN, T1.*
    FROM ${TABLE_NAME} T1
    WHERE MOVED_TO_ITN = 'N'
    ORDER BY CN_SERIAL
) T2 WHERE RN <= #{unit}


SELECT T2.* FROM (
    SELECT ROW_NUMBER() OVER(ORDER BY WERKS, CN_PART_REV, CN_PDM_PART_NO, CN_JOB_NO) AS RN, T1.*
    FROM ITN_ITEM T1
    WHERE MOVED_TO_DOCS = 'N'
    ORDER BY WERKS, CN_PART_REV, CN_PDM_PART_NO, CN_JOB_NO
) T2 WHERE RN <= #{unit}


SELECT T2.* FROM (
    SELECT ROW_NUMBER() OVER(ORDER BY CN_SERIAL) AS RN, T1.*
    FROM ${TABLE_NAME} T1
    WHERE MOVED = 'N'
    ORDER BY CN_SERIAL
) T2 WHERE RN <= #{unit}

